--
-- Table structure for table `racing_form`
--

DROP TABLE IF EXISTS `racing_form`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `racing_form` (
  `race_id` bigint NOT NULL,
  `frame_number` int NOT NULL,
  `horse_number` int NOT NULL,
  `horse_name` varchar(64) COLLATE utf8mb4_unicode_ci NOT NULL,
  `sex_age` varchar(8) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `hair` varchar(8) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `birthyear` tinyint unsigned DEFAULT NULL,
  `birthymonth` tinyint unsigned DEFAULT NULL,
  `sire` varchar(64) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `dam` varchar(64) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `broodmare_sire` varchar(64) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `carried_weight` decimal(4,1) DEFAULT NULL,
  `jockey_name` varchar(64) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `affiliation` varchar(16) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `trainer_name` varchar(64) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `owner` varchar(64) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `breeder` varchar(64) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `odds_morning` decimal(8,2) DEFAULT NULL,
  `horse_weight` int DEFAULT NULL,
  `horse_weight_diff` int DEFAULT NULL,
  `draw_number` int DEFAULT NULL,
  `remarks` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `raw_json` json DEFAULT NULL,
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`race_id`,`horse_number`),
  KEY `idx_racing_form_race` (`race_id`),
  KEY `idx_racing_form_jockey` (`jockey_name`),
  KEY `idx_racing_form_trainer` (`trainer_name`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

